mapper.update:
UPDATE knowledge_folder_runs
SET status = 'CANCELLING',
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND status = 'RUNNING'

mapper.delete:
DELETE FROM knowledge_folder_runs
WHERE scope_type = #{scopeType}
  AND ((#{scopeId} IS NULL AND scope_id IS NULL) OR scope_id = #{scopeId})
